// Amazon 3D Printing Filament Bestsellers — Markets Config
// Fill in FILL_IN_URL placeholders with the correct Amazon bestsellers URLs before running.
// Pattern: https://www.amazon.{domain}/Best-Sellers-.../zgbs/{dept}/{category-id}/
const markets = [
  { market: 'US', column: 'B', url: 'https://www.amazon.com/Best-Sellers-Industrial-Scientific-3D-Printing-Filament/zgbs/industrial/6066129011/' },
  { market: 'CA', column: 'C', url: 'FILL_IN_URL' },
  { market: 'UK', column: 'F', url: 'FILL_IN_URL' },
  { market: 'DE', column: 'G', url: 'FILL_IN_URL' },
  { market: 'FR', column: 'H', url: 'FILL_IN_URL' },
  { market: 'ES', column: 'I', url: 'FILL_IN_URL' },
  { market: 'IT', column: 'J', url: 'FILL_IN_URL' },
  { market: 'NL', column: 'K', url: 'FILL_IN_URL' },
  { market: 'JP', column: 'S', url: 'FILL_IN_URL' },
  { market: 'AU', column: 'U', url: 'FILL_IN_URL' }
];

// Filter out markets with placeholder URLs so partial runs work
const readyMarkets = markets.filter(m => !m.url.startsWith('FILL_IN'));
console.log(`Running ${readyMarkets.length}/${markets.length} markets`);

return readyMarkets.map(m => ({ json: m }));

const apifyResponse = $input.item.json;
const datasetId = apifyResponse.data && apifyResponse.data.defaultDatasetId;
const column = $('Loop Over Markets').item.json.column;
const market = $('Loop Over Markets').item.json.market;

if (!datasetId) {
  throw new Error(`No datasetId returned for market ${market}. Apify response: ${JSON.stringify(apifyResponse).slice(0, 200)}`);
}

console.log(`Market ${market}: datasetId = ${datasetId}`);
return [{ json: { datasetId, column, market } }];

// Get column + market from upstream (before the HTTP request replaced the item)
const column = $('Extract Dataset ID').item.json.column;
const market = $('Extract Dataset ID').item.json.market;

// n8n may return the dataset as multiple items (split) or as a single item (array)
const allItems = $input.all();
let brands;
if (allItems.length > 1) {
  // n8n split the JSON array into separate items
  brands = allItems.map(item => item.json);
} else {
  // Whole response came as a single item
  const data = allItems[0].json;
  brands = Array.isArray(data) ? data : (data.items || []);
}

if (!brands.length) {
  throw new Error(`No items returned from Apify dataset for market ${market}`);
}

// Sort by position (rank on page)
brands.sort((a, b) => (a.position || 999) - (b.position || 999));

// Extract brand name: first word of product title
const brandList = brands.slice(0, 100).map(item => {
  const name = item.name || item.title || '';
  return name.trim().split(/\s+/)[0] || 'UNKNOWN';
});

// Pad to exactly 100 rows
while (brandList.length < 100) brandList.push('');

// Format for Google Sheets API: array of single-element row arrays
const valuesForSheets = brandList.map(brand => [brand]);

console.log(`Market ${market}: extracted ${brandList.filter(b => b).length} brands`);
return [{ json: { column, market, values: valuesForSheets } }];
